1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type Step =
5	  | { op: "quote"; items: Item[] }
6	  | { op: "claim"; policy: number; incident: Incident };
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const FIRST_INSURANCE_MULTIPLIER = 1.1;
19	const PROCESSING_FEE = 5;
20	
21	const ceilToWholeG = (amount: number): number =>
22	  Math.ceil(Math.round(amount * 100) / 100);
23	
24	const COMPONENT_BUNDLE_PRICE = 60;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	const CURSED_SURCHARGE = 1.5;
28	const ENCHANTMENT_SURCHARGE = 1.3;
29	const ENCHANTMENT_THRESHOLD = 5;
30	
31	const itemMultiplier = (item: Item): number =>
32	  (item.cursed ? CURSED_SURCHARGE : 1) *
33	  ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD ? ENCHANTMENT_SURCHARGE : 1);
34	
35	const sumItemsAtUnitPrice = (items: Item[], unitPrice: number): number =>
36	  items.reduce((sum, item) => sum + unitPrice * itemMultiplier(item), 0);
37	
38	const baseForGroup = (type: string, group: Item[]): number => {
39	  const unitPrice = BASE_PREMIUM[type] ?? 0;
40	  if (!COMPONENT_TYPES.has(type)) {
41	    return sumItemsAtUnitPrice(group, unitPrice);
42	  }
43	  const bundleCount = Math.floor(group.length / 3);
44	  const singles = group.slice(bundleCount * 3);
45	  return bundleCount * COMPONENT_BUNDLE_PRICE + sumItemsAtUnitPrice(singles, unitPrice);
46	};
47	
48	const groupByType = (items: Item[]): Map<string, Item[]> => {
49	  const groups = new Map<string, Item[]>();
50	  for (const item of items) {
51	    const list = groups.get(item.type) ?? [];
52	    list.push(item);
53	    groups.set(item.type, list);
54	  }
55	  return groups;
56	};
57	
58	const LOYALTY_DISCOUNT = 0.8;
59	const LOYALTY_YEARS_THRESHOLD = 2;
60	
61	const customerMultiplier = (customer: Scenario["customer"]): number =>
62	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 1;
63	
64	const baseForItems = (items: Item[]): number =>
65	  [...groupByType(items)].reduce(
66	    (sum, [type, group]) => sum + baseForGroup(type, group),
67	    0,
68	  );
69	
70	const SUBSEQUENT_CONTRACT_DISCOUNT = 0.85;
71	
72	const contractMultiplier = (quoteIndex: number): number =>
73	  quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : SUBSEQUENT_CONTRACT_DISCOUNT;
74	
75	const quote = (items: Item[], customer: Scenario["customer"], quoteIndex: number): number => {
76	  const adjusted = baseForItems(items) * customerMultiplier(customer) * contractMultiplier(quoteIndex);
77	  return ceilToWholeG(adjusted) + PROCESSING_FEE;
78	};
79	
80	const DEDUCTIBLE = 100;
81	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
82	const HIGH_ENCHANTMENT_THRESHOLD = 8;
83	
84	const damageReimbursement = (damage: Damage, policyItems: Item[]): number => {
85	  const item = policyItems.find((i) => i.type === damage.itemType);
86	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
87	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT;
88	  }
89	  return damage.amount;
90	};
91	
92	const claim = (incident: Incident, policyItems: Item[]): number => {
93	  const reimbursed = incident.damages.reduce(
94	    (sum, d) => sum + damageReimbursement(d, policyItems),
95	    0,
96	  );
97	  return Math.max(0, reimbursed - DEDUCTIBLE);
98	};
99	
100	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
101	  let quoteIndex = 0;
102	  const policiesByStep = new Map<number, Item[]>();
103	  const results = scenario.steps.map((step, stepIndex) => {
104	    if (step.op === "quote") {
105	      policiesByStep.set(stepIndex, step.items);
106	      return { premium: quote(step.items, scenario.customer, quoteIndex++) };
107	    }
108	    return { payout: claim(step.incident, policiesByStep.get(step.policy) ?? []) };
109	  });
110	  return { results };
111	};
